props.type:
shape({
  /**
   * Sets the color context of the progress bar to one of CoreUI’s themed colors
   *
   * @values 'primary', 'secondary', 'success', 'danger', 'warning', 'info', 'dark', 'light'
   */
  color: Color,
  /**
   * The percent to progress the ProgressBar (out of 100).
   */
  value: {
    type: Number,
    default: 0,
  },
})
